#include <bits/stdc++.h>

using namespace std;

class Task2 {
 public:
	void solve() {
		read_input();
		print_output(get_result());
	}

 private:
	static constexpr int NMAX = (int) 1e5 + 5;

	int n, m, source;

	vector<int> adj[NMAX];
	vector<int> revtopsort;  /* reverse top sort */

	void read_input() {
		ifstream fin("ferate.in");
		fin >> n >> m >> source;
		for (int i = 1, x, y; i <= m; i++) {
			fin >> x >> y;
			adj[x].push_back(y);  // arc (x, y)
		}
		fin.close();
	}

	/* function for the last check */
	void DFS_check(int source, vector<bool> &visited) {
		visited[source] = true;

		for (auto &neigh : adj[source]) {
			if (!visited[neigh]) {
				DFS_check(neigh, visited);
			}
		}
	}

	/* Tarjan SCCs in order to determine the topological sort of the graph */
	void DFS_topsort(int source, vector<int> &parent, int &timestamp,
					vector<int> &found, vector<int> &low_link,
					vector<int> &nodes_stack, vector<bool> &memberStack) {
        int initial_pos = nodes_stack.size();
        found[source] = ++timestamp;

        low_link[source] = found[source];
        nodes_stack.push_back(source);
        memberStack[source] = true;

        for (auto& neigh : adj[source]) {
            if (parent[neigh] != -1) {
                if (memberStack[neigh] == true) {
                    low_link[source] = min(low_link[source], found[neigh]);
                }

                continue;
            }

            parent[neigh] = source;

            DFS_topsort(neigh, parent, timestamp, found,
						low_link, nodes_stack, memberStack);

            low_link[source] = min(low_link[source], low_link[neigh]);
        }

        if (low_link[source] == found[source]) {
            int size = nodes_stack.size();

            for (int i = size - 1; i >= initial_pos; i--) {
                revtopsort.push_back(nodes_stack[i]);
                memberStack[nodes_stack[i]] = false;
                nodes_stack.pop_back();
            }
        }
    }

	int get_result() {
		/* Initialise structs for Tarjan's algorithm */
		vector<int> parent(n + 1, -1);
        vector<int> found(n + 1, INT_MAX);
        vector<int> low_link(n + 1, INT_MAX);
        vector<bool> memberStack(n + 1, false);

        vector<int> nodes_stack;
		int result = 0;

        int timestamp = 0;
        for (int node = 1; node <= n; node++) {
            if (parent[node] == -1) {
                parent[node] = node;

                DFS_topsort(node, parent, timestamp, found,
							low_link, nodes_stack, memberStack);
            }
        }

		vector<bool> visited(n + 1, false);

		/* Do a DFS check in order to eliminate each connected component */
		DFS_check(source, visited);

		/* When we move to another component --> we start a new DFS */
		for (int i = n - 1; i >= 0; i--) {
			if (!visited[revtopsort[i]]) {
				result++;

				DFS_check(revtopsort[i], visited);
			}
		}

		return result;
	}

	void print_output(int added) {
		ofstream fout("ferate.out");
		fout << added << "\n";
		fout.close();
	}
};

int main() {
	auto* task = new (nothrow) Task2();
	if (!task) {
		cerr << "new task failed!\n";
		return -1;
	}
	task->solve();
	delete task;
	return 0;
}

import java.io.BufferedReader;
import java.io.FileNotFoundException;
import java.io.IOException;
import java.io.PrintStream;
import java.io.Reader;
import java.util.ArrayList;
import java.util.LinkedList;
import java.util.Queue;
import java.util.Stack;
import java.util.StringTokenizer;

public class Ferate {

	public static void main(String[] args) {
		MyScanner sc;
		try {
			sc = new MyScanner(new java.io.FileReader("ferate.in"));
		} catch (java.io.FileNotFoundException e) {
			throw new RuntimeException(e);
		}

		int N = sc.nextInt();
		int M = sc.nextInt();
		int startNode = sc.nextInt();
		FerateGraph graph = new FerateGraph(N, startNode);

		for (int i = 0; i < M; i++) {
			int from, to;
			from = sc.nextInt();
			to = sc.nextInt();
			graph.addEdge(from, to);
		}

		int result = graph.findSingles(graph.findSccs());
		try (var printer = new PrintStream("ferate.out")) {
			printer.print(result);
		} catch (FileNotFoundException e) {
			throw new RuntimeException(e);
		}
	}

	/**
	 * A class for buffering read operations, inspired from here:
	 * https://pastebin.com/XGUjEyMN.
	 */
	private static class MyScanner {
		private final BufferedReader br;
		private StringTokenizer st;

		public MyScanner(Reader reader) {
			br = new BufferedReader(reader);
		}

		public String next() {
			while (st == null || !st.hasMoreElements()) {
				try {
					st = new StringTokenizer(br.readLine());
				} catch (IOException e) {
					e.printStackTrace();
				}
			}
			return st.nextToken();
		}

		public int nextInt() {
			return Integer.parseInt(next());
		}

		public long nextLong() {
			return Long.parseLong(next());
		}

		public double nextDouble() {
			return Double.parseDouble(next());
		}

		public String nextLine() {
			String str = "";
			try {
				str = br.readLine();
			} catch (IOException e) {
				e.printStackTrace();
			}
			return str;
		}
	}

	private static class FerateGraph {
		private final int vertices;
		private final int startNode;
		private final ArrayList<Integer>[] adjacencyList;
		private final ArrayList<Integer>[] neighborList;
		private int time;

		public FerateGraph(int vertices, int startNode) {
			this.vertices = vertices;
			this.startNode = startNode;
			adjacencyList = new ArrayList[vertices + 1];
			neighborList = new ArrayList[vertices + 1];
			for (int i = 1; i <= vertices; ++i) {
				adjacencyList[i] = new ArrayList<>();
				neighborList[i] = new ArrayList<>();
			}
		}

		public void addEdge(int source, int destination) {
			adjacencyList[source].add(destination);
			neighborList[destination].add(source);
		}

		public int findSingles(ArrayList<ArrayList<Integer>> sccs) {
			int singles = 0;
			boolean standalone;
			for (ArrayList<Integer> scc : sccs) {
				if (scc.contains(startNode)) {
					continue;
				}
				standalone = true;
				for (int nodeInScc : scc) {
					for (int neighbor : neighborList[nodeInScc]) {
						if (!scc.contains(neighbor)) {
							standalone = false;
							break;
						}
					}
					if (!standalone) {
						break;
					}
				}
				if (standalone) {
					singles++;
				}

			}
			return singles;
		}

		public ArrayList<ArrayList<Integer>> findSccs() {
			ArrayList<ArrayList<Integer>> sccs = new ArrayList<>();
			Stack<Integer> stack = new Stack<>();
			int[] low = new int[vertices + 1];
			int[] ids = new int[vertices + 1];
			boolean[] onStack = new boolean[vertices + 1];

			for (int i = 1; i <= vertices; i++) {
				if (ids[i] == 0) {
					dfsScc(i, low, ids, stack, onStack, sccs);
				}
			}

			return sccs;
		}

		private void dfsScc(int node, int[] low, int[] ids, Stack<Integer> stack,
			boolean[] onStack, ArrayList<ArrayList<Integer>> sccs) {
			stack.push(node);
			onStack[node] = true;
			ids[node] = low[node] = ++time;

			for (int neighbor : adjacencyList[node]) {
				if (ids[neighbor] == 0) {
					dfsScc(neighbor, low, ids, stack, onStack, sccs);
				}
				if (onStack[neighbor]) {
					low[node] = Math.min(low[node], low[neighbor]);
				}
			}

			if (ids[node] == low[node]) {
				ArrayList<Integer> scc = new ArrayList<>();
				int poppedNode;
				do {
					poppedNode = stack.pop();
					onStack[poppedNode] = false;
					scc.add(poppedNode);
				} while (poppedNode != node);
				sccs.add(scc);
			}
		}
	}
}
